def extract_tar_file(tar_path, dest_dir):
    """
    Extracts a tar file to a specified destination directory.
    
    Args:
        tar_path (str): The path to the tar file.
        dest_dir (str): The destination directory where the tar file will be extracted.
        
    Returns:
        None
    """

